class Solution:
    def integerReplacement(self, n):
        """
        :type n: int
        :rtype: int
        """
        steps = 0

        while n != 1:
            if n % 2 == 0:
                n //= 2
            else:
                # For odd, choose +1 or -1 strategically
                # +1 is better if n%4==1 (except n=3)
                if n == 3 or n % 4 == 3:
                    n += 1
                else:
                    n -= 1
            steps += 1

        return steps
